// ---- Textyl 3-step pixel process animation ----

const G = 100, S = 5;

const BG     = '#10353C';
const TEAL   = '#5cddc6';
const T_MID  = '#2f6f66';
const T_DARK = '#1d4a55';
const LILAC  = '#c0b3fa';
const LIGHT  = '#ecf3f1';

const S1_END = 4.2, S2_END = 9.4, TOTAL = 14.2;

const noise = [];
for (let y = 0; y < G; y++) { noise[y] = [];
  for (let x = 0; x < G; x++) {
    noise[y][x] = Math.sin(x*0.35 + y*0.21) + Math.sin(x*0.13 - y*0.31) + Math.sin((x+y)*0.07)*1.4;
  }
}
const rnd = [];
for (let y = 0; y < G; y++) { rnd[y] = [];
  for (let x = 0; x < G; x++) rnd[y][x] = Math.random();
}

// ----- scene 1 geometry -----
const SPH_CX = 50, SPH_CY = 48, SPH_R = 36;

function drape(x, y) {
  const dx = x - SPH_CX;
  const half = 45 + 1.5 * Math.sin(x * 0.11);
  if (Math.abs(dx) > half) return -1;
  let top;
  if (Math.abs(dx) < SPH_R) top = 46 - Math.sqrt(SPH_R*SPH_R - dx*dx);
  else top = 46 + (Math.abs(dx) - SPH_R) * 1.5;
  const hem = 76 + 4.5 * Math.sin(x * 0.17 + 1.2) + 1.5 * Math.sin(x * 0.36);
  if (y < top || y > hem) return -1;
  const dy = y - 46;
  const lightF = 1.08 - (dx + 45) * 0.0035;
  const foldB = (0.30 + 0.5 * Math.pow(Math.abs(Math.sin(dx * 0.16 + 0.7)), 1.8)) * lightF
                - (y - 66) * 0.004;
  let b;
  if (dx*dx + dy*dy < SPH_R*SPH_R) {
    const z = Math.sqrt(SPH_R*SPH_R - dx*dx - dy*dy);
    const sphereB = Math.max(0, (-dx*0.45 - dy*0.45 + z*0.77) / SPH_R);
    const w = Math.min(1, Math.max(0, (56 - y) / 14));
    b = w * sphereB + (1 - w) * foldB;
  } else {
    b = foldB;
  }
  b += noise[y][x] * 0.015;
  return Math.min(1, Math.max(0.05, b));
}

const TEAL_RAMP = ['#16424d','#1d4a55','#2f6f66','#3f8f82','#4aa392','#5cddc6','#7ee8d4','#9aeede'];
function tealShade(b) { return TEAL_RAMP[Math.round(Math.min(1, Math.max(0, b)) * 7)]; }

function shadeLerp(b, dark, light, n) {
  const q = Math.round(Math.min(1, Math.max(0, b)) * (n - 1)) / (n - 1);
  return 'rgb(' + dark.map((d, i) => Math.round(d + (light[i] - d) * q)).join(',') + ')';
}

function lilacSphere(x, y) {
  const dx = x - SPH_CX, dy = y - SPH_CY;
  if (dx*dx + dy*dy > SPH_R*SPH_R) return -1;
  const z = Math.sqrt(SPH_R*SPH_R - dx*dx - dy*dy);
  let b = Math.max(0, (-dx*0.45 - dy*0.45 + z*0.77) / SPH_R);
  return Math.min(1, Math.max(0.05, b));
}

const spikes = [];
for (let i = 0; i < 10; i++) {
  spikes.push({
    ang: i * 0.628 + (Math.random() - 0.5) * 0.45,
    len: 26 + Math.random() * 18,
    w:   3.5 + Math.random() * 2.2,
  });
}
function drawBurst(cx, cy, t, alpha) {
  const tg = t - 2.2;
  if (tg <= 0) return;
  const tip  = ease(tg / 0.3);
  const base = ease((tg - 0.16) / 0.34);
  if (base >= 1) return;
  for (const sp of spikes) {
    const s0 = 8;
    const dx = Math.cos(sp.ang), dy = Math.sin(sp.ang);
    for (let s = s0 + base * sp.len; s < s0 + tip * sp.len; s += 0.7) {
      const hw = sp.w * (1 - (s - s0) / sp.len);
      const xx = cx + dx * s, yy = cy + dy * s;
      for (let k = -hw; k <= hw; k += 0.7)
        cell(Math.round(xx - dy * k), Math.round(yy + dx * k), '#e3dcff', alpha);
    }
  }
}

function weave(x, y) {
  const t = ((x + y*2) % 6 + 6) % 6;
  if (t < 2) return 2;
  if (t < 4) return 1;
  return 0;
}
const WEAVE_COLS = [T_DARK, T_MID, TEAL];

const GLYPH1 = ['.X.','XX.','.X.','.X.','XXX'];
const GLYPH0 = ['XXX','X.X','X.X','X.X','XXX'];
const glyphs = [];
for (let i = 0; i < 260; i++) {
  glyphs.push({ x: Math.floor(Math.random()*96), y: Math.floor(Math.random()*94), one: Math.random() < 0.5 });
}

