const shirt = [];
const OUTL = [];
for (let y = 0; y < G; y++) {
  shirt[y] = new Array(G).fill(false);
  OUTL[y] = new Array(G).fill(0);
  for (let x = 0; x < G; x++) {
    OUTL[y][x] = parseInt(SHIRT_HEX[y][x], 16) / 15;
    shirt[y][x] = SHIRT_MASK[y][x] === '1';
  }
}
const SHIRT_BTNS = [];   // buttons live in the artwork


// soft drape shading used over the weave fill (0..1 shadow amount)
function shirtShadow(x, y) {
  if (y < 18) return 0;
  const f = Math.pow(Math.abs(Math.sin(x * 0.17 + Math.sin(y * 0.05) * 1.2)), 2.4);
  const side = Math.max(0, 1 - Math.abs(Math.abs(x - 50) - 18) / 5) * 0.4;
  return Math.min(1, f * 0.55 + side);
}

function drawShirt(alpha, fillR) {
  for (let y = 0; y < G; y++) for (let x = 0; x < G; x++) {
    // weave fill first, under the outline; same ragged edge as the suck-in
    if (shirt[y][x] && fillR > 0) {
      const ed = fillR - Math.hypot(x - 50, y - 55);
      if (ed > 0 && !(ed < 5 && rnd[y][x] < (5 - ed) * 0.22)) {
        cell(x, y, WEAVE_COLS[weave(x, y)], alpha);
        const sh = shirtShadow(x, y);
        if (sh > 0.25) cell(x, y, '#0b2227', alpha * (sh - 0.25) * 0.5);
      }
    }
    const v = OUTL[y][x];
    if (v > 0.05) cell(x, y, LIGHT, alpha * v * 0.95);
  }
  for (const [x, y] of SHIRT_BTNS) {
    cell(x, y, LIGHT, alpha); cell(x + 1, y, LIGHT, alpha);
    cell(x, y + 1, LIGHT, alpha); cell(x + 1, y + 1, LIGHT, alpha);
  }
}

// ----- folder icon (front panel leans like the reference) -----
const FOLD_OUT = '#0d262c', FOLD_BACK = '#d9b15f', FOLD_FRONT = '#f0d189';
function fillCells(x0, y0, x1, y1, col, a) {
  for (let y = y0; y <= y1; y++) for (let x = x0; x <= x1; x++) cell(x, y, col, a);
}
function drawFolder(fx, fy, open, alpha) {
  const slot = Math.round(open * 3);
  fillCells(fx, fy, fx + 6, fy + 2, FOLD_BACK, alpha);                 // tab
  fillCells(fx, fy + 2, fx + 17, fy + 12, FOLD_BACK, alpha);           // back panel
  rectOutline(fx, fy + 2, fx + 17, fy + 12, FOLD_OUT, alpha);
  rectOutline(fx, fy, fx + 6, fy + 2, FOLD_OUT, alpha);
  if (slot > 0) fillCells(fx + 1, fy + 3, fx + 16, fy + 2 + slot, FOLD_OUT, alpha);   // open slot
  // front panel: parallelogram, top edge shifted right
  const fTop = fy + 3 + slot, fBot = fy + 12;
  for (let y = fTop; y <= fBot; y++) {
    const sk = Math.round((y - fBot) * -0.3);
    for (let x = fx + 1; x <= fx + 16; x++) cell(x + sk, y, FOLD_FRONT, alpha);
    cell(fx + 1 + sk, y, FOLD_OUT, alpha);
    cell(fx + 16 + sk, y, FOLD_OUT, alpha);
    if (y === fTop || y === fBot)
      for (let x = fx + 1; x <= fx + 16; x++) cell(x + sk, y, FOLD_OUT, alpha);
  }
}

const CURSOR = ['X......','XX.....','XXX....','XXXX...','XXXXX..','XXXXXX.','..XX...','...XX..'];

// ---------- drawing helpers ----------
function cell(x, y, col, a) {
  if (x < 0 || y < 0 || x >= G || y >= G) return;
  ctx.globalAlpha = a === undefined ? 1 : a;
  ctx.fillStyle = col;
  ctx.fillRect(x*S, y*S, S-0.8, S-0.8);
  ctx.globalAlpha = 1;
}
function rectOutline(x0, y0, x1, y1, col, a) {
  for (let x = x0; x <= x1; x++) { cell(x, y0, col, a); cell(x, y1, col, a); }
  for (let y = y0; y <= y1; y++) { cell(x0, y, col, a); cell(x1, y, col, a); }
}
function drawGlyph(g, gx, gy, col, a) {
  const rows = g ? GLYPH1 : GLYPH0;
  for (let r = 0; r < 5; r++) for (let c = 0; c < 3; c++)
    if (rows[r][c] === 'X') cell(gx + c, gy + r, col, a);
}
function drawCursor(cx, cy, a) {
  for (let r = 0; r < CURSOR.length; r++) for (let c = 0; c < 7; c++)
    if (CURSOR[r][c] === 'X') cell(cx + c, cy + r, LIGHT, a);
}
const ease = t => t < 0 ? 0 : t > 1 ? 1 : t*t*(3 - 2*t);

// ---------- scenes ----------
const PH_W = 40, PH_Y0 = 20, PH_Y1 = 84;
function drawPhone(px, alpha) {
  const x1 = px + PH_W - 1;
  for (let y = PH_Y0; y <= PH_Y1; y++) for (let x = px; x <= x1; x++) {
    const inScreen = x >= px + 3 && x <= x1 - 3 && y >= PH_Y0 + 3 && y <= PH_Y1 - 11;
    if (inScreen) continue;
    const cxd = Math.min(x - px, x1 - x), cyd = Math.min(y - PH_Y0, PH_Y1 - y);
    if (cxd + cyd < 2) continue;
    cell(x, y, T_MID, alpha);
  }
  cell(px + 19, PH_Y1 - 5, '#9aeede', alpha); cell(px + 20, PH_Y1 - 5, '#9aeede', alpha);
  cell(px + 19, PH_Y1 - 6, '#9aeede', alpha); cell(px + 20, PH_Y1 - 6, '#9aeede', alpha);
}

